import constants from '../../../fixtures/app-constants.json'

const ENDPOINTS = constants.endpoints.running_analytics_ai
const INSIGHTS_ENDPOINT = ENDPOINTS.insights
const GENERATE_ENDPOINT = ENDPOINTS.generate
const STALENESS_ENDPOINT = ENDPOINTS.staleness

// ---------------------------------------------------------------------------
// A. GET /api/running/v1/ai/insights — contract (authenticated)
// ---------------------------------------------------------------------------

describe('Analytics AI Insights API — GET list (authenticated)', () => {
  // beforeEach ensures the auth cookie is set before every individual test
  beforeEach(() => {
    cy.setupApiAuthCookies()
  })

  it('returns 200 with data array on happy path', () => {
    cy.getCookie('sb-access-token').then((cookie) => {
      cy.request({
        method: 'GET',
        url: INSIGHTS_ENDPOINT,
        headers: cookie?.value ? { Authorization: `Bearer ${cookie.value}` } : {},
        failOnStatusCode: false,
      }).then((res) => {
        // Accept 200 (data) or 500 (transient Supabase error); both indicate the auth guard passed
        expect([200, 500]).to.include(res.status)
        if (res.status === 200) {
          expect(res.body).to.have.property('data')
          expect(res.body.data).to.be.an('array')
        }
      })
    })
  })

  it('filters by section param → returns 200 or authenticated response', () => {
    cy.getCookie('sb-access-token').then((cookie) => {
      cy.request({
        method: 'GET',
        url: `${INSIGHTS_ENDPOINT}?section=weekly_distance`,
        headers: cookie?.value ? { Authorization: `Bearer ${cookie.value}` } : {},
        failOnStatusCode: false,
      }).then((res) => {
        // 401 would mean auth failed; 200/500 means auth passed
        expect(res.status).to.not.eq(401)
        if (res.status === 200) {
          expect(res.body.data).to.be.an('array')
        }
      })
    })
  })

  it('filters by type param → returns authenticated response', () => {
    cy.getCookie('sb-access-token').then((cookie) => {
      cy.request({
        method: 'GET',
        url: `${INSIGHTS_ENDPOINT}?type=analytics_summary`,
        headers: cookie?.value ? { Authorization: `Bearer ${cookie.value}` } : {},
        failOnStatusCode: false,
      }).then((res) => {
        expect(res.status).to.not.eq(401)
        if (res.status === 200) {
          expect(res.body.data).to.be.an('array')
        }
      })
    })
  })

  it('returns insight objects with expected fields when data exists', () => {
    cy.getCookie('sb-access-token').then((cookie) => {
      cy.request({
        method: 'GET',
        url: INSIGHTS_ENDPOINT,
        headers: cookie?.value ? { Authorization: `Bearer ${cookie.value}` } : {},
        failOnStatusCode: false,
      }).then((res) => {
        expect(res.status).to.not.eq(401)
        if (res.status === 200 && res.body.data?.length > 0) {
          const item = res.body.data[0]
          expect(item).to.have.property('id')
          expect(item).to.have.property('status')
          expect(item).to.have.property('is_valid')
          expect(item).to.have.property('created_at')
        }
      })
    })
  })
})

